ADMIN_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
# Find primary and check rs status
kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  "mongodb://admin-user:${ADMIN_PASS}@localhost:27017/admin?directConnection=true" \
  --eval "
var status = rs.status();
status.members.forEach(m => print(m.name, m.stateStr));
print('self:', rs.isMaster().ismaster);
" 2>&1 | grep -v "^Current\|^Connecting\|^Using\|^For mongosh\|free cloud\|monitoring\|www.mongodb\|^------\|^   \|^To " | grep -v "^$"

ADMIN_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
APP_PASS=$(kubectl get secret app-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
RO_PASS=$(kubectl get secret readonly-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)

kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  "mongodb://admin-user:${ADMIN_PASS}@localhost:27017/admin?directConnection=true" \
  --eval "
var adminDb = db.getSiblingDB('admin');
var appdb   = db.getSiblingDB('appdb');

// 1. Create reportingRole in appdb (idempotent)
var existingRole = appdb.getRoles({rolesInfo: {role: 'reportingRole', db: 'appdb'}, showPrivileges: true});
// Simpler: just try/create
try {
  appdb.createRole({
    role: 'reportingRole',
    privileges: [
      {
        resource: { db: 'appdb', collection: 'reports' },
        actions: ['find', 'aggregate', 'listCollections', 'collStats']
      }
    ],
    roles: []
  });
  print('reportingRole created in appdb');
} catch(e) {
  if (e.code === 51002 || String(e).indexOf('already') !== -1) {
    print('reportingRole already exists - skipping creation');
  } else {
    throw e;
  }
}

// 2. Create app-user (idempotent)
if (!adminDb.getUser('app-user')) {
  adminDb.createUser({
    user: 'app-user',
    pwd: '${APP_PASS}',
    roles: [{ role: 'readWrite', db: 'appdb' }]
  });
  print('app-user created');
} else {
  // Ensure roles are correct
  adminDb.updateUser('app-user', { roles: [{ role: 'readWrite', db: 'appdb' }] });
  adminDb.updateUser('app-user', { pwd: '${APP_PASS}' });
  print('app-user already exists - updated password and roles');
}

// 3. Grant reportingRole to readonly-user
var roUser = adminDb.getUser('readonly-user');
if (roUser) {
  var hasRead      = roUser.roles.some(r => r.role === 'read'          && r.db === 'appdb');
  var hasReporting = roUser.roles.some(r => r.role === 'reportingRole' && r.db === 'appdb');
  var toGrant = [];
  if (!hasRead)      toGrant.push({ role: 'read',          db: 'appdb' });
  if (!hasReporting) toGrant.push({ role: 'reportingRole', db: 'appdb' });
  if (toGrant.length > 0) {
    adminDb.grantRolesToUser('readonly-user', toGrant);
    print('Granted to readonly-user: ' + JSON.stringify(toGrant));
  } else {
    print('readonly-user already has both read and reportingRole on appdb');
  }
} else {
  adminDb.createUser({
    user: 'readonly-user',
    pwd: '${RO_PASS}',
    roles: [
      { role: 'read',          db: 'appdb' },
      { role: 'reportingRole', db: 'appdb' }
    ]
  });
  print('readonly-user created with read + reportingRole');
}

print('');
print('=== FINAL STATE ===');
var roFinal  = adminDb.getUser('readonly-user');
var appFinal = adminDb.getUser('app-user');
print('app-user roles:      ', JSON.stringify(appFinal.roles));
print('readonly-user roles: ', JSON.stringify(roFinal.roles));
" 2>&1 | grep -E "created|updated|already|Granted|FINAL|roles|Error|error|Exception" | grep -v "^--"

